using System;using System.Collections.Generic;using System.Data;using System.Drawing;using System.IO;using System.Windows.Forms;
namespace PremiumLivingFurnitureWinForms;public class SalesOrderForm:Form{readonly ComboBox customer=new(){DropDownStyle=ComboBoxStyle.DropDownList},salesUser=new(){DropDownStyle=ComboBoxStyle.DropDownList};readonly TextBox orderNo=new();readonly DateTimePicker date=new(){Format=DateTimePickerFormat.Short};readonly DataGridView grid=new();readonly Label total=new();public string OrderNo=>orderNo.Text.Trim();public int CustomerId=>customer.SelectedItem is LookupItem i?i.Id:0;public int SalesUserId=>salesUser.SelectedItem is LookupItem i?i.Id:0;public string Status=>"Confirmed";public string Priority=>"Normal";public string OrderDate=>date.Value.ToString("yyyy-MM-dd");public List<SalesOrderItemDraft> Items{get;}=new();public SalesOrderForm(){Text="Add Sales Order - Multiple Products";StartPosition=FormStartPosition.CenterParent;Size=new Size(1120,760);Font=Theme.DefaultFont;BackColor=Theme.AppBg;var root=new TableLayoutPanel{Dock=DockStyle.Fill,RowCount=4,ColumnCount=1,Padding=new Padding(24),BackColor=Theme.AppBg};root.RowStyles.Add(new RowStyle(SizeType.Absolute,120));root.RowStyles.Add(new RowStyle(SizeType.Percent,100));root.RowStyles.Add(new RowStyle(SizeType.Absolute,42));root.RowStyles.Add(new RowStyle(SizeType.Absolute,58));root.Controls.Add(Header(),0,0);root.Controls.Add(Grid(),0,1);root.Controls.Add(total,0,2);root.Controls.Add(Buttons(),0,3);Controls.Add(root);LoadData();Recalculate();}Control Header(){orderNo.ReadOnly=true;orderNo.Text=Database.GenerateNextCode("Orders","OrderNo","SO-2026","-",4);var p=new TableLayoutPanel{Dock=DockStyle.Fill,ColumnCount=4,RowCount=2,BackColor=Color.White,Padding=new Padding(16)};for(int i=0;i<4;i++)p.ColumnStyles.Add(new ColumnStyle(SizeType.Percent,25));AddField(p,"Order No",orderNo,0);AddField(p,"Customer",customer,1);AddField(p,"Sales User",salesUser,2);AddField(p,"Date",date,3);return p;}static void AddField(TableLayoutPanel p,string label,Control control,int col){p.Controls.Add(new Label{Text=label,Dock=DockStyle.Top,ForeColor=Theme.Muted,Font=new Font("Segoe UI",9,FontStyle.Bold)},col,0);control.Dock=DockStyle.Top;p.Controls.Add(control,col,1);}Control Grid(){grid.Dock=DockStyle.Fill;grid.AllowUserToAddRows=false;grid.RowHeadersVisible=false;grid.AutoSizeColumnsMode=DataGridViewAutoSizeColumnsMode.Fill;grid.RowTemplate.Height=86;grid.Columns.Add(new DataGridViewCheckBoxColumn{Name="Selected",HeaderText="Select"});grid.Columns.Add(new DataGridViewTextBoxColumn{Name="ProductId",Visible=false});grid.Columns.Add(new DataGridViewImageColumn{Name="ProductImage",HeaderText="Picture",ImageLayout=DataGridViewImageCellLayout.Zoom,Width=110});grid.Columns.Add(new DataGridViewTextBoxColumn{Name="ImagePath",Visible=false});grid.Columns.Add(new DataGridViewTextBoxColumn{Name="ProductName",HeaderText="Product"});grid.Columns.Add(new DataGridViewTextBoxColumn{Name="UnitPrice",HeaderText="Unit Price",ReadOnly=true});grid.Columns.Add(new DataGridViewTextBoxColumn{Name="Quantity",HeaderText="Quantity"});grid.Columns.Add(new DataGridViewTextBoxColumn{Name="Discount",HeaderText="Discount"});grid.Columns.Add(new DataGridViewTextBoxColumn{Name="LineTotal",HeaderText="Line Total",ReadOnly=true});grid.CellValueChanged+=(_,_)=>Recalculate();grid.CurrentCellDirtyStateChanged+=(_,_)=>{if(grid.IsCurrentCellDirty)grid.CommitEdit(DataGridViewDataErrorContexts.Commit);};return grid;}Control Buttons(){var buttons=new FlowLayoutPanel{Dock=DockStyle.Fill,FlowDirection=FlowDirection.RightToLeft,BackColor=Theme.AppBg};var save=Theme.PrimaryButton("Save Order",130);var cancel=Theme.SecondaryButton("Cancel",110);save.Click+=(_,_)=>SaveOrder();cancel.Click+=(_,_)=>DialogResult=DialogResult.Cancel;buttons.Controls.Add(save);buttons.Controls.Add(cancel);return buttons;}void LoadData(){foreach(var c in Database.GetLookup("Customers"))customer.Items.Add(c);foreach(var u in Database.GetLookup("Users"))salesUser.Items.Add(u);if(customer.Items.Count>0)customer.SelectedIndex=0;if(salesUser.Items.Count>0)salesUser.SelectedIndex=0;try{Database.EnsureProductImagePathColumn();}catch{}foreach(DataRow r in Database.GetTable("Products").Rows){string imagePath=r.Table.Columns.Contains("ImagePath")?Convert.ToString(r["ImagePath"])??"":"";grid.Rows.Add(false,r["Id"],LoadProductThumbnail(imagePath,96,64),imagePath,r["ProductName"],r["UnitPrice"],1,0,r["UnitPrice"]);}}public static Image LoadProductThumbnail(string imagePath,int width,int height){try{string path=ResolveImagePath(imagePath);if(!File.Exists(path))return PlaceholderImage(width,height);using var original=Image.FromFile(path);var thumb=new Bitmap(width,height);using var g=Graphics.FromImage(thumb);g.Clear(Color.White);g.InterpolationMode=System.Drawing.Drawing2D.InterpolationMode.HighQualityBicubic;double ratio=Math.Min((double)(width-8)/original.Width,(double)(height-8)/original.Height);int w=Math.Max(1,(int)(original.Width*ratio)),h=Math.Max(1,(int)(original.Height*ratio));g.DrawImage(original,new Rectangle((width-w)/2,(height-h)/2,w,h));return thumb;}catch{return PlaceholderImage(width,height);}}public static Image PlaceholderImage(int width,int height){var img=new Bitmap(width,height);using var g=Graphics.FromImage(img);g.Clear(Color.FromArgb(241,245,249));using var pen=new Pen(Color.FromArgb(203,213,225));g.DrawRectangle(pen,1,1,width-2,height-2);using var brush=new SolidBrush(Color.FromArgb(100,116,139));using var font=new Font("Segoe UI",8,FontStyle.Bold);using var sf=new StringFormat{Alignment=StringAlignment.Center,LineAlignment=StringAlignment.Center};g.DrawString("No Image",font,brush,new RectangleF(0,0,width,height),sf);return img;}static string ResolveImagePath(string imagePath){if(string.IsNullOrWhiteSpace(imagePath))return"";if(Path.IsPathRooted(imagePath))return imagePath;return Path.Combine(AppDomain.CurrentDomain.BaseDirectory,imagePath.Replace("/",Path.DirectorySeparatorChar.ToString()));}static decimal ToDecimal(object? v)=>decimal.TryParse(Convert.ToString(v),out var n)?n:0;void Recalculate(){decimal grand=0;foreach(DataGridViewRow row in grid.Rows){bool selected=Convert.ToBoolean(row.Cells["Selected"].Value??false);decimal line=Math.Max(0,ToDecimal(row.Cells["UnitPrice"].Value)*ToDecimal(row.Cells["Quantity"].Value)-ToDecimal(row.Cells["Discount"].Value));row.Cells["LineTotal"].Value=line.ToString("0.00");if(selected)grand+=line;}total.Text=$"Selected products total: HK$ {grand:N2}";total.ForeColor=Theme.Primary;total.Font=new Font("Segoe UI",12,FontStyle.Bold);total.TextAlign=ContentAlignment.MiddleRight;}void SaveOrder(){Items.Clear();foreach(DataGridViewRow row in grid.Rows){if(!Convert.ToBoolean(row.Cells["Selected"].Value??false))continue;int id=Convert.ToInt32(row.Cells["ProductId"].Value);string name=Convert.ToString(row.Cells["ProductName"].Value)??"";decimal unit=ToDecimal(row.Cells["UnitPrice"].Value),discount=ToDecimal(row.Cells["Discount"].Value);int qty=Math.Max(1,Convert.ToInt32(ToDecimal(row.Cells["Quantity"].Value)));Items.Add(new SalesOrderItemDraft(id,name,qty,unit,discount,Math.Max(0,unit*qty-discount)));}if(Items.Count==0){MessageBox.Show("Please select at least one product.");return;}DialogResult=DialogResult.OK;}}